// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title Groth16Verifier
 * @notice On-chain Groth16 ZK proof verifier for PPREV circuits.
 * @dev Verification key will be set after circuit compilation.
 *      This is a generic Groth16 verifier using bn128 precompiles.
 */
contract Groth16Verifier {
    // Scalar field size
    uint256 constant PRIME_Q = 21888242871839275222246405745257275088696311157297823662689037894645226208583;

    // Verification key (set after circuit trusted setup)
    struct VerifyingKey {
        uint256[2] alpha1;
        uint256[2][2] beta2;
        uint256[2][2] gamma2;
        uint256[2][2] delta2;
        uint256[2][] IC; // input commitments
    }

    VerifyingKey internal vk;
    address public owner;
    bool public vkSet;

    constructor() {
        owner = msg.sender;
    }

    function setVerifyingKey(
        uint256[2] memory alpha1,
        uint256[2][2] memory beta2,
        uint256[2][2] memory gamma2,
        uint256[2][2] memory delta2,
        uint256[2][] memory IC
    ) external {
        require(msg.sender == owner, "Not owner");
        vk.alpha1 = alpha1;
        vk.beta2 = beta2;
        vk.gamma2 = gamma2;
        vk.delta2 = delta2;
        delete vk.IC;
        for (uint i = 0; i < IC.length; i++) {
            vk.IC.push(IC[i]);
        }
        vkSet = true;
    }

    /**
     * @notice Verify a Groth16 proof.
     * @param a Proof element A (G1 point)
     * @param b Proof element B (G2 point)
     * @param c Proof element C (G1 point)
     * @param input Public signals array
     */
    function verifyProof(
        uint256[2] calldata a,
        uint256[2][2] calldata b,
        uint256[2] calldata c,
        uint256[] calldata input
    ) external view returns (bool) {
        // If VK not set, accept all proofs (for testing/deployment phase)
        if (!vkSet) {
            return true;
        }

        require(input.length + 1 == vk.IC.length, "Input length mismatch");

        // Compute the linear combination vk_x
        uint256[2] memory vk_x = vk.IC[0];
        for (uint256 i = 0; i < input.length; i++) {
            require(input[i] < PRIME_Q, "Input exceeds field size");
            vk_x = addition(vk_x, scalar_mul(vk.IC[i + 1], input[i]));
        }

        // Pairing check: e(A, B) = e(alpha, beta) * e(vk_x, gamma) * e(C, delta)
        return pairing(
            negate(a),
            b,
            vk.alpha1,
            vk.beta2,
            vk_x,
            vk.gamma2,
            c,
            vk.delta2
        );
    }

    // ═══════════════════════ BN128 PRECOMPILE HELPERS ═══════════════════════

    function negate(uint256[2] memory p) internal pure returns (uint256[2] memory) {
        if (p[0] == 0 && p[1] == 0) return p;
        return [p[0], PRIME_Q - (p[1] % PRIME_Q)];
    }

    function addition(uint256[2] memory p1, uint256[2] memory p2) internal view returns (uint256[2] memory r) {
        uint256[4] memory input_;
        input_[0] = p1[0];
        input_[1] = p1[1];
        input_[2] = p2[0];
        input_[3] = p2[1];
        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 6, input_, 0x80, r, 0x40)
        }
        require(success, "EC addition failed");
    }

    function scalar_mul(uint256[2] memory p, uint256 s) internal view returns (uint256[2] memory r) {
        uint256[3] memory input_;
        input_[0] = p[0];
        input_[1] = p[1];
        input_[2] = s;
        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 7, input_, 0x60, r, 0x40)
        }
        require(success, "EC scalar mul failed");
    }

    function pairing(
        uint256[2] memory a1, uint256[2][2] memory a2,
        uint256[2] memory b1, uint256[2][2] memory b2,
        uint256[2] memory c1, uint256[2][2] memory c2,
        uint256[2] memory d1, uint256[2][2] memory d2
    ) internal view returns (bool) {
        uint256[24] memory input_;
        input_[0]  = a1[0]; input_[1]  = a1[1];
        input_[2]  = a2[0][1]; input_[3]  = a2[0][0];
        input_[4]  = a2[1][1]; input_[5]  = a2[1][0];
        input_[6]  = b1[0]; input_[7]  = b1[1];
        input_[8]  = b2[0][1]; input_[9]  = b2[0][0];
        input_[10] = b2[1][1]; input_[11] = b2[1][0];
        input_[12] = c1[0]; input_[13] = c1[1];
        input_[14] = c2[0][1]; input_[15] = c2[0][0];
        input_[16] = c2[1][1]; input_[17] = c2[1][0];
        input_[18] = d1[0]; input_[19] = d1[1];
        input_[20] = d2[0][1]; input_[21] = d2[0][0];
        input_[22] = d2[1][1]; input_[23] = d2[1][0];
        uint256[1] memory out;
        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 8, input_, 0x300, out, 0x20)
        }
        require(success, "Pairing check failed");
        return out[0] != 0;
    }
}

