// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title PPREV - Privacy-Preserving Real Estate Verification
 * @notice Unified smart contract managing listing registration, tenant application
 *         with escrow, and settlement via ZK proof verification.
 * @dev Implements Pi_own, Pi_elig, and Pi_trans protocol phases.
 */
contract PPREV {
    // ═══════════════════════ ENUMS ═══════════════════════
    enum ListingStatus { NONE, ACTIVE, LOCKED, SETTLED, EXPIRED }
    enum AppStatus { NONE, PENDING_TRANSFER, EXPIRED, SETTLED }

    // ═══════════════════════ STRUCTS ═══════════════════════
    struct Listing {
        address owner;
        bytes32 adHash;
        bytes32 policyId;
        uint256 deposit;
        uint256 reqEscrow;
        ListingStatus status;
        uint256 createdAt;
    }

    struct Application {
        address tenant;
        bytes32 adHash;
        uint256 escrowAmount;
        AppStatus status;
        uint256 expiresAt;
    }

    // ═══════════════════════ STATE ═══════════════════════
    address public owner;
    IGroth16Verifier public zkVerifier;

    uint256 public freshnessDelta = 30 minutes;
    uint256 public escrowTimeout = 7 days;
    uint256 public minDeposit = 0.001 ether;
    uint256 public slashPercent = 10; // percentage of escrow slashed on timeout

    mapping(bytes32 => Listing) public listings;
    mapping(bytes32 => Application) public applications;
    mapping(bytes32 => bool) public usedNonces;

    bytes32[] public listingIds;
    bytes32[] public applicationIds;

    // ═══════════════════════ EVENTS ═══════════════════════
    event ListingRegistered(bytes32 indexed adHash, address indexed owner, bytes32 policyId);
    event ApplicationSubmitted(bytes32 indexed appId, bytes32 indexed adHash, address indexed tenant);
    event SettlementCompleted(bytes32 indexed appId, bytes32 indexed adHash, address indexed owner);
    event ApplicationExpired(bytes32 indexed appId, bytes32 indexed adHash);
    event EscrowSlashed(bytes32 indexed appId, uint256 slashedAmount, uint256 refunded);

    // ═══════════════════════ MODIFIERS ═══════════════════════
    modifier onlyOwner() {
        require(msg.sender == owner, "Not contract owner");
        _;
    }

    // ═══════════════════════ CONSTRUCTOR ═══════════════════════
    constructor(address _zkVerifier) {
        owner = msg.sender;
        zkVerifier = IGroth16Verifier(_zkVerifier);
    }

    // ═══════════════════════ PHASE 1: LISTING REGISTRATION (Pi_own) ═══════════════════════
    /**
     * @notice Register a property listing with ZK proof of ownership.
     * @param adHash       H(metadata || policyId) - listing commitment
     * @param policyId     Policy identifier defining required tenant proofs
     * @param reqEscrow    Required escrow amount for tenant applications
     * @param nonce        Single-use nonce embedded in TLSNotary transcript
     * @param tAuth        Timestamp from the authenticated transcript
     */
    function registerListing(
        bytes32 adHash,
        bytes32 policyId,
        uint256 reqEscrow,
        bytes32 nonce,
        uint256 tAuth,
        uint256[2] calldata proof_a,
        uint256[2][2] calldata proof_b,
        uint256[2] calldata proof_c,
        uint256[] calldata pubSignals
    ) external payable {
        // 1. Check listing does not already exist
        require(listings[adHash].status == ListingStatus.NONE, "Listing already exists");

        // 2. Deposit check
        require(msg.value >= minDeposit, "Insufficient deposit");

        // 3. Freshness check
        require(block.timestamp - tAuth <= freshnessDelta, "Proof too old");

        // 4. Nonce uniqueness
        require(!usedNonces[nonce], "Nonce already used");

        // 5. ZK proof verification
        require(
            zkVerifier.verifyProof(proof_a, proof_b, proof_c, pubSignals),
            "ZK proof verification failed"
        );

        // 6. State transition
        usedNonces[nonce] = true;
        listings[adHash] = Listing({
            owner: msg.sender,
            adHash: adHash,
            policyId: policyId,
            deposit: msg.value,
            reqEscrow: reqEscrow,
            status: ListingStatus.ACTIVE,
            createdAt: block.timestamp
        });
        listingIds.push(adHash);

        emit ListingRegistered(adHash, msg.sender, policyId);
    }

    // ═══════════════════════ PHASE 2: TENANT APPLICATION (Pi_elig) ═══════════════════════
    /**
     * @notice Apply for a listing with ZK proof of eligibility + escrow deposit.
     * @param adHash       Target listing commitment
     * @param nonce        Single-use nonce for this application
     * @param tAuth        Timestamp from the authenticated transcript
     */
    function applyForListing(
        bytes32 adHash,
        bytes32 nonce,
        uint256 tAuth,
        uint256[2] calldata proof_a,
        uint256[2][2] calldata proof_b,
        uint256[2] calldata proof_c,
        uint256[] calldata pubSignals
    ) external payable {
        Listing storage listing = listings[adHash];

        // 1. Listing must be ACTIVE
        require(listing.status == ListingStatus.ACTIVE, "Listing not active");

        // 2. Escrow deposit check
        require(msg.value >= listing.reqEscrow, "Insufficient escrow");

        // 3. Freshness check
        require(block.timestamp - tAuth <= freshnessDelta, "Proof too old");

        // 4. Nonce uniqueness
        require(!usedNonces[nonce], "Nonce already used");

        // 5. No duplicate application
        bytes32 appId = keccak256(abi.encodePacked(adHash, msg.sender, nonce));
        require(applications[appId].status == AppStatus.NONE, "Duplicate application");

        // 6. ZK proof verification
        require(
            zkVerifier.verifyProof(proof_a, proof_b, proof_c, pubSignals),
            "ZK proof verification failed"
        );

        // 7. State transitions
        usedNonces[nonce] = true;
        listing.status = ListingStatus.LOCKED;

        applications[appId] = Application({
            tenant: msg.sender,
            adHash: adHash,
            escrowAmount: msg.value,
            status: AppStatus.PENDING_TRANSFER,
            expiresAt: block.timestamp + escrowTimeout
        });
        applicationIds.push(appId);

        emit ApplicationSubmitted(appId, adHash, msg.sender);
    }

    // ═══════════════════════ PHASE 3: SETTLEMENT (Pi_trans) ═══════════════════════
    /**
     * @notice Complete settlement with ZK proof of transfer.
     * @param appId        Application identifier
     * @param nonce        Single-use nonce for this settlement
     * @param tAuth        Timestamp from the authenticated transcript
     */
    function settleApplication(
        bytes32 appId,
        bytes32 nonce,
        uint256 tAuth,
        uint256[2] calldata proof_a,
        uint256[2][2] calldata proof_b,
        uint256[2] calldata proof_c,
        uint256[] calldata pubSignals
    ) external {
        Application storage app = applications[appId];
        Listing storage listing = listings[app.adHash];

        // 1. Only listing owner can settle
        require(msg.sender == listing.owner, "Not listing owner");

        // 2. Application must be PENDING_TRANSFER
        require(app.status == AppStatus.PENDING_TRANSFER, "Invalid app status");

        // 3. Within escrow timeout
        require(block.timestamp <= app.expiresAt, "Escrow expired");

        // 4. Freshness check
        require(block.timestamp - tAuth <= freshnessDelta, "Proof too old");

        // 5. Nonce uniqueness
        require(!usedNonces[nonce], "Nonce already used");

        // 6. ZK proof verification
        require(
            zkVerifier.verifyProof(proof_a, proof_b, proof_c, pubSignals),
            "ZK proof verification failed"
        );

        // 7. Atomic state transition + fund release
        usedNonces[nonce] = true;
        app.status = AppStatus.SETTLED;
        listing.status = ListingStatus.SETTLED;

        // Transfer escrow + listing deposit to owner
        uint256 payout = app.escrowAmount + listing.deposit;
        (bool sent, ) = listing.owner.call{value: payout}("");
        require(sent, "Transfer failed");

        emit SettlementCompleted(appId, app.adHash, listing.owner);
    }

    // ═══════════════════════ TIMEOUT / SLASHING ═══════════════════════
    /**
     * @notice Handle expired escrow: slash griefing fee, refund remainder, revert listing.
     * @param appId Application identifier
     */
    function expireApplication(bytes32 appId) external {
        Application storage app = applications[appId];
        Listing storage listing = listings[app.adHash];

        require(app.status == AppStatus.PENDING_TRANSFER, "Not pending");
        require(block.timestamp > app.expiresAt, "Not yet expired");

        // Slash and refund
        uint256 slashAmount = (app.escrowAmount * slashPercent) / 100;
        uint256 refundAmount = app.escrowAmount - slashAmount;

        app.status = AppStatus.EXPIRED;
        listing.status = ListingStatus.ACTIVE;

        // Refund tenant (minus slash)
        if (refundAmount > 0) {
            (bool sent, ) = app.tenant.call{value: refundAmount}("");
            require(sent, "Refund failed");
        }

        // Slash goes to listing owner as compensation
        if (slashAmount > 0) {
            (bool sent2, ) = listing.owner.call{value: slashAmount}("");
            require(sent2, "Slash transfer failed");
        }

        emit ApplicationExpired(appId, app.adHash);
        emit EscrowSlashed(appId, slashAmount, refundAmount);
    }

    // ═══════════════════════ VIEW FUNCTIONS ═══════════════════════
    function getListingCount() external view returns (uint256) {
        return listingIds.length;
    }

    function getApplicationCount() external view returns (uint256) {
        return applicationIds.length;
    }

    function getListingDetails(bytes32 adHash) external view returns (
        address listingOwner,
        bytes32 policyId,
        uint256 reqEscrow,
        ListingStatus status
    ) {
        Listing storage l = listings[adHash];
        return (l.owner, l.policyId, l.reqEscrow, l.status);
    }

    function getApplicationDetails(bytes32 appId) external view returns (
        address tenant,
        bytes32 adHash,
        uint256 escrowAmount,
        AppStatus status,
        uint256 expiresAt
    ) {
        Application storage a = applications[appId];
        return (a.tenant, a.adHash, a.escrowAmount, a.status, a.expiresAt);
    }

    // ═══════════════════════ ADMIN ═══════════════════════
    function updateFreshnessDelta(uint256 _delta) external onlyOwner {
        freshnessDelta = _delta;
    }

    function updateEscrowTimeout(uint256 _timeout) external onlyOwner {
        escrowTimeout = _timeout;
    }

    function updateMinDeposit(uint256 _min) external onlyOwner {
        minDeposit = _min;
    }
}

// ═══════════════════════ INTERFACE ═══════════════════════
interface IGroth16Verifier {
    function verifyProof(
        uint256[2] calldata a,
        uint256[2][2] calldata b,
        uint256[2] calldata c,
        uint256[] calldata input
    ) external view returns (bool);
}

